SELECT i.intervention_name, i.intervention_type
FROM interventions i
WHERE i.administered_date > '2022-04-01';

SELECT pf.intervention_id, COUNT(DISTINCT pf.patient_id) AS unique_patient_count
FROM patient_feedback AS pf
GROUP BY pf.intervention_id;

SELECT provider_id, COUNT(intervention_id) AS NumberOfInterventions
FROM provider_interventions
GROUP BY provider_id;

SELECT intervention_name, description 
FROM interventions 
WHERE effectiveness_rating = (SELECT MAX(effectiveness_rating) FROM interventions);

SELECT AVG(julianday('now') - julianday(outcomes.assessment_period)) / 30 AS average_months 
FROM outcomes 
WHERE outcomes.improvement_level = 'Level1';
